// Determine what documents are needed based on line of business
const payload = $input.first().json.payload;
const lob = payload.line_of_business || 'auto';

let requiredDocs = [];
let templateName = 'general_application_packet';

switch(lob.toLowerCase()) {
  case 'auto':
    requiredDocs = ['drivers_license', 'current_dec_page', 'vehicle_registration'];
    templateName = 'auto_application_packet';
    break;
  case 'home':
  case 'homeowners':
    requiredDocs = ['current_dec_page', 'property_photos', 'mortgage_statement'];
    templateName = 'home_application_packet';
    break;
  case 'commercial':
  case 'business':
    requiredDocs = ['current_policies', 'loss_runs', 'financial_statements', 'business_license'];
    templateName = 'commercial_application_packet';
    break;
  case 'life':
    requiredDocs = ['medical_history', 'beneficiary_info'];
    templateName = 'life_application_packet';
    break;
  default:
    requiredDocs = ['current_dec_page', 'id_document'];
}

return {
  quote_id: $input.first().json.entity_id,
  account_id: payload.account_id,
  agency_workspace_id: $input.first().json.agency_workspace_id,
  line_of_business: lob,
  required_docs: requiredDocs,
  template_name: templateName
};
